/*
 * NQueens.java
 * Solves the N-Queens problem using a backtracking algorithm.
 */
import java.util.Scanner;
public class NQueens {
   public static void solve(int N) {
      int[][] board = new int[10001][10001];
      for (int i = 1; i <= N; i++) {
         for (int j = 1; j <= N; j++) board[i][j] = 0;
      }
      if (backtrack(board, 1)) {
         for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
               if (board[i][j] == 1) System.out.print(i + ' ' + j + '
');
            }
         }
         return;
      }
      System.out.print('NO');
   }

   public static boolean isValid(int[][] board, int row, int col) {
      for (int i = 1; i <= col; i++) {
         if (board[row][i] == 1) return false;
      }
      return true;
   }

   public static boolean backtrack(int[][] board, int col) {
      if (col >= N) return true;
      for (int row = 1; row <= N; row++) {
         if (!isValid(board, row, col)) continue;
         board[row][col] = 1;
         if (backtrack(board, col + 1)) return true;
         board[row][col] = 0;
      }
      return false;
   }

   public static void main(String[] args) {
      Scanner scanner = new Scanner(System.in);
      int N = scanner.nextInt();
      solve(N);
   }
}

